#!/bin/bash
sed -i 's/    pub(crate) fn window_id_for_surface(/    pub(crate) fn window_for_surface(\n        \&self,\n        surface: \&smithay::reexports::wayland_server::protocol::wl_surface::WlSurface,\n    ) -> Option<Window> {\n        use smithay::desktop::WindowSurfaceType;\n\n        self.space.elements().find(|w| {\n            if w.wl_surface().as_deref() == Some(surface) {\n                return true;\n            }\n            w.surface_under((0.0, 0.0), WindowSurfaceType::ALL)\n                .map(|(hit_surface, _)| hit_surface == *surface)\n                .unwrap_or(false)\n        }).cloned()\n    }\n\n    pub(crate) fn window_id_for_surface(/g' src/backend/wayland/compositor/state.rs
